package com.lightevents.dashboard;
import com.lightevents.events.*; import com.lightevents.payments.TransactionRepository; import com.lightevents.profiles.UserProfileRepository; import org.springframework.web.bind.annotation.*; import java.util.Map;
@RestController @RequestMapping("/api/dashboard")
public class DashboardController { private final EventRepository events; private final AttendeeRepository attendees; private final UserProfileRepository profiles; private final TransactionRepository tx; public DashboardController(EventRepository events, AttendeeRepository attendees, UserProfileRepository profiles, TransactionRepository tx){this.events=events;this.attendees=attendees;this.profiles=profiles;this.tx=tx;} @GetMapping("/summary") public Map<String,Object> summary(){return Map.of("events",events.count(),"attendees",attendees.count(),"checkedIn",attendees.countByStatus(CheckInStatus.CHECKED_IN),"profiles",profiles.count(),"transactions",tx.count(),"markets",java.util.List.of("Côte d’Ivoire","Sénégal","Cameroun","RDC","Bénin","Togo"));} }
